                    ser.serialize(valueElem, gen, provider);
                } else {
                    ser.serializeWithType(valueElem, gen, provider, typeSer);
                }
            } catch (Exception e) {
                wrapAndThrow(provider, e, value, String.valueOf(keyElem));
            }
        }
